import { useReward } from 'react-rewards';
import styles from './RewardButton.module.css';

/**
 * RewardButton
 *
 * Props:
 *  - entry: RewardEntry (from configs/rewards.js)
 *
 * Como usar fora deste playground:
 *   import { useReward } from 'react-rewards';
 *   const { reward } = useReward('meuId', entry.type, entry.config);
 */
export default function RewardButton({ entry }) {
  const { id, type, icon, title, desc, tag, color, config } = entry;

  const { reward, isAnimating } = useReward(id, type, {
    ...config,
    zIndex: 9999,
  });

  return (
    <button
      className={`${styles.btn} ${isAnimating ? styles.animating : ''}`}
      onClick={reward}
      disabled={isAnimating}
      aria-label={`Disparar ${title}`}
    >
      {/* Âncora — ponto de origem da animação */}
      <span id={id} className={styles.anchor} aria-hidden="true" />

      <span className={`${styles.badge} ${styles[`badge_${color}`]}`}>
        {tag}
      </span>

      <span className={styles.icon}>{icon}</span>
      <span className={styles.title}>{title}</span>
      <span className={styles.desc}>{desc}</span>
    </button>
  );
}
